import random

# Grid dimensions
GRID_WIDTH = 10
GRID_HEIGHT = 20

# Define tetromino shapes as lists of (x, y) offsets
TETROMINO_SHAPES = {
    'I': [(0,0), (1,0), (2,0), (3,0)],
    'O': [(0,0), (1,0), (0,1), (1,1)],
    'T': [(1,0), (0,1), (1,1), (2,1)],
    'S': [(1,0), (2,0), (0,1), (1,1)],
    'Z': [(0,0), (1,0), (1,1), (2,1)],
    'J': [(0,0), (0,1), (1,1), (2,1)],
    'L': [(2,0), (0,1), (1,1), (2,1)],
}

# Map each shape to a gem color
GEM_COLORS = {
    'I': 'cyan',
    'O': 'yellow',
    'T': 'purple',
    'S': 'green',
    'Z': 'red',
    'J': 'blue',
    'L': 'orange',
}

class Gem:
    def __init__(self, color):
        self.color = color
        self.marked_for_clear = False

    def __repr__(self):
        return f"Gem({self.color[0].upper()})"

class GameGrid:
    def __init__(self, width=GRID_WIDTH, height=GRID_HEIGHT):
        self.width = width
        self.height = height
        self.cells = [[None for _ in range(width)] for _ in range(height)]

    def in_bounds(self, x, y):
        return 0 <= x < self.width and 0 <= y < self.height

    def set_cell(self, x, y, value):
        if not self.in_bounds(x, y):
            raise IndexError(f"Position out of bounds: ({x},{y})")
        self.cells[y][x] = value

    def get_cell(self, x, y):
        if not self.in_bounds(x, y):
            raise IndexError(f"Position out of bounds: ({x},{y})")
        return self.cells[y][x]

    def __repr__(self):
        rows = []
        for row in self.cells:
            rows.append(' '.join(str(cell) if cell else '.' for cell in row))
        return '\n'.join(rows)

class Tetromino:
    def __init__(self, shape_type):
        self.shape_type = shape_type
        self.blocks = TETROMINO_SHAPES[shape_type]
        self.color = GEM_COLORS[shape_type]
        self.x = (GRID_WIDTH // 2) - 2
        self.y = 0
        self.rotation = 0  # degrees

    def get_cells(self, x_offset=0, y_offset=0, blocks=None):
        cells = []
        for bx, by in blocks or self.blocks:
            cells.append((self.x + bx + x_offset, self.y + by + y_offset))
        return cells

    def can_move(self, grid, dx, dy):
        for x, y in self.get_cells(dx, dy):
            if not grid.in_bounds(x, y) or grid.cells[y][x] is not None:
                return False
        return True

    def move(self, grid, dx, dy):
        if self.can_move(grid, dx, dy):
            self.x += dx
            self.y += dy
            return True
        return False

    def rotate(self, grid):
        new_blocks = []
        for bx, by in self.blocks:
            rx = by
            ry = 3 - bx
            new_blocks.append((rx, ry))
        for x, y in self.get_cells(0, 0, new_blocks):
            if not grid.in_bounds(x, y) or grid.cells[y][x] is not None:
                return False
        self.blocks = new_blocks
        self.rotation = (self.rotation + 90) % 360
        return True

    def drop_one(self, grid):
        if not self.move(grid, 0, 1):
            self.lock(grid)
            return False
        return True

    def lock(self, grid):
        """
        Place a Gem instance in each occupied cell when locking.
        """
        for x, y in self.get_cells():
            if not grid.in_bounds(x, y):
                raise ValueError(f"Cannot lock out of bounds at ({x},{y})")
            gem = Gem(self.color)
            grid.set_cell(x, y, gem)

def spawn_tetromino():
    shape = random.choice(list(TETROMINO_SHAPES.keys()))
    return Tetromino(shape)

# Example usage
if __name__ == "__main__":
    grid = GameGrid()
    tet = spawn_tetromino()
    # Move tetromino down until it locks
    while tet.drop_one(grid):
        pass
    print(grid)

